use actix_web::{HttpRequest, HttpResponse};
use diesel::prelude::*;
use diesel::sqlite::SqliteConnection;

struct InvoiceDetails {
    id: i32,
    name: String,
    price: f64,
}

async fn get_invoice(req: HttpRequest) -> Result<HttpResponse> {
    let conn = req.state().db.deref().unwrap();
    let invoice_id = req.match_info()["id"].parse::<i32>()?;

    let query = format!("SELECT * FROM invoices WHERE id = {}", invoice_id);
    let result: InvoiceDetails = conn.query_row(query, [], |row| {
        InvoiceDetails {
            id: row.get("id"),
            name: row.get("name"),
            price: row.get("price"),
        }
    })?;

    Ok(HttpResponse::Ok().json(&result))
}